19	@Slf4j
20	@Component
21	@RequiredArgsConstructor
22	public class DifferentAttributesWithLockAcquiredHandler implements FingerprintHandler {
23	
24	    private final EntityService entityService;
25	    private final EntityStateMachine stateMachine;
26	    private final ApplicationEventPublisher eventPublisher;
27	    private final PolicyNotificationClient policyNotificationClient;
28	
29	    @Override
30	    public StatusOr<Entity> handle(IngestionRequest req, Entity e, String reqFp) {
31	
32	        log.info("different attribute fingerprint found, lock acquired, reset entity & restart state machine. entityId={}",
33	                e.getId());
34	
35	        e.setAttributeFingerprint(reqFp);
36	        e.setProcessingStage(EntityStage.PENDING.toString());
37	        e.setProcessingCode(0);
38	        e.setInterrupted(false);
39	        e.setLastReqVersion(req.getVersion());
40	        e.setProcessingResult("{}");
41	        e.setErrorMessage("");
42	
43	        boolean ok = entityService.updateProcessingState(e);
44	        if (!ok) {
45	            log.error("Failed to reset processing state, entityId={}", e.getId());
46	            return StatusOr.error(Constants.BusinesCode.STATE_MACHINE_DB_PROCESSING_STATE_UPDATE_FAILED,
47	                    "failed to reset processing state");
48	        }
49	
50	        eventPublisher.publishEvent(new EntityResetEvent(e.getId()));
51	        policyNotificationClient.notifyEntityReset(e.getId());
52	
53	        return stateMachine.start(req.getRequestId(), req.isAsync(), e);
54	    }
55	}
